using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResult _evaluationResult;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate to get metrics on the small dataset
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);

        var metrics = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;

        // Compute per-category metrics from the best fold
        var bestFold = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var bestModel = bestFold.Model;
        var scored = bestModel.Transform(dataView);
        var confusionMatrix = _mlContext.MulticlassClassification.Evaluate(scored, "Label").ConfusionMatrix;
        var classes = confusionMatrix.PerClassPrecision;

        // Extract label names from the key column
        var labelColumn = scored.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        scored.Schema["Label"].GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        var perCategory = new List<CategoryMetric>();
        for (int i = 0; i < _categoryLabels.Length; i++)
        {
            perCategory.Add(new CategoryMetric
            {
                Category = _categoryLabels[i],
                Precision = Math.Round(confusionMatrix.PerClassPrecision[i], 4),
                Recall = Math.Round(confusionMatrix.PerClassRecall[i], 4),
                F1Score = confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i] > 0
                    ? Math.Round(2 * confusionMatrix.PerClassPrecision[i] * confusionMatrix.PerClassRecall[i]
                        / (confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i]), 4)
                    : 0
            });
        }

        _evaluationResult = new EvaluationResult
        {
            MacroAccuracy = Math.Round(metrics.MacroAccuracy, 4),
            MicroAccuracy = Math.Round(metrics.MicroAccuracy, 4),
            LogLoss = Math.Round(metrics.LogLoss, 4),
            LogLossReduction = Math.Round(metrics.LogLossReduction, 4),
            TrainingSampleCount = (int)_mlContext.Data.CreateEnumerable<TicketData>(dataView, false).Count(),
            PerCategory = perCategory
        };

        // Train final model on full dataset
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public TicketPredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categoryLabels[i]] = MathF.Round(prediction.Score[i], 4);
        }

        return new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationResult GetEvaluationMetrics() => _evaluationResult;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResult> GetMetrics()
    {
        return Ok(_classifier.GetEvaluationMetrics());
    }
}

